import Link from '../../components/Link';
const _not_found = {title: "Unknown", jsx: <><h2 id="eidolon-not_found-unknown">Unknown</h2>
<p>Unable to find the requested unchained eidolon subtype.</p>
</>};
const _aberrant = {title: "Aberrant", jsx: <><h2 id="eidolon-aberrant-aberrant">Aberrant</h2>
<p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 18</Link><br/>Alien entities from the farthest stars, the lightless depths of the Darklands, the sea itself, or even a lunatic's nightmares have long intrigued summoners who become obsessed with the monstrous form. While most summoners call upon outsiders from the Great Beyond, some discover the secret to summoning alien entities from strange corners of the Material Plane. These summoned minions are known as aberrant eidolons. Aberrant eidolons share many abilities and physical features with the nonoutsider aberrations that dwell in forgotten or nameless reaches of reality, but these malformed entities are still outsiders like any other eidolon for the purposes of determining which spells affect them.</p>
<p><strong>Alignment:</strong> Chaotic evil, chaotic neutral, neutral, or neutral evil.</p>
<p><strong>Base Form:</strong> Aberrant (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/grab">grab</Link> [tentacle mass], <Link to="/unchevolution/tentacle_mass">tentacle mass</Link>), biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>), quadruped (bite, limbs [legs, 2]), or serpentine (bite, grab [bite], <Link to="/unchevolution/reach">reach</Link> [bite], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions:</strong> Starting at 1st level, aberrant eidolons gain the following class skills in place of those normally gained by eidolons: Escape Artist, Intimidate, Knowledge (pick one), Perception, Stealth, and Climb, Fly, or Swim (pick one). The summoner can choose four additional skills to be class skills for his eidolon. Aberrant eidolons count as both aberrations and outsiders for spells and effects. They gain a +4 racial bonus on saving throws against mind-affecting effects.</p>
<p>At 4th level, aberrant eidolons add 1 point to their evolution pools.</p>
<p>At 8th level, aberrant eidolons gain immunity to mind-affecting effects (including morale bonuses).</p>
<p>At 12th level, aberrant eidolons gain DR 5/slashing. They also gain the <Link to="/unchevolution/blindsense">blindsense</Link> evolution as a bonus evolution.</p>
<p>At 16th level, aberrant eidolons gain the <Link to="/unchevolution/blindsight">blindsight</Link> evolution. They also gain <Link to="/umr/telepathy">telepathy</Link> with a range of up to 100 feet.</p>
<p>At 20th level, aberrant eidolons gain the ability to use <Link to="/spell/transmogrify">transmogrify</Link> as a <Link to="/feat/quicken_spell_like_ability">quickened spell-like ability</Link> once per day. These eidolons can gain the benefit of a transmogrify spell any number of times per day.</p>
</>};
const _aeon = {title: "Aeon", jsx: <><h2 id="eidolon-aeon-aeon">Aeon</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 24</Link><br/>Created to monitor a specific duality, an aeon eidolon often proves frustratingly headstrong in enforcing its own interpretation of balance.</p>
<p><strong>Alignment</strong> Neutral.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]) or serpentine (limbs [arms], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/slam">slam</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, aeon eidolons gain the <Link to="/family/aeon">envisaging ability</Link>. Aeon eidolons halve the armor and natural armor bonuses they gain per level, but gain an equal deflection bonus to their AC. They also gain a +4 bonus on saving throws against poison.</p>
<p>At 4th level, aeon eidolons gain the benefits of the <Link to="/magic-enh/moderate_fortification">moderate fortification</Link> armor special ability and cannot be tripped.</p>
<p>At 8th level, aeon eidolons gain the <Link to="/unchevolution/flight">flight</Link> evolution (using magic) with a speed equal to their base speed.</p>
<p>At 12th level, aeon eidolons gain the ability to influence either emotions or time as a standard action, as chosen by the summoner. Whenever the summoner gains a level, he can change which ability the eidolon influences. When affecting emotions, an aeon eidolon affects up to five targets within 30 feet as <Link to="/spell/crushing_despair">crushing despair</Link>. A target can negate this effect with a successful Will save (DC = 14 + the eidolon's Charisma modifier). For each target that fails its save, the eidolon can affect one other creature within 30 feet as <Link to="/spell/good_hope">good hope</Link>. The caster level equals the eidolon's Hit Dice, and the save DC is equal to 10 + half the eidolon's Hit Dice + the eidolon's Charisma modifier. When affecting time, the ability functions in the same way, but the eidolon affects primary targets as <Link to="/spell/slow">slow</Link> and secondary targets as <Link to="/spell/haste">haste</Link>. The eidolon can use this ability once per day for every 5 Hit Dice it has.</p>
<p>At 16th level, aeon eidolons become immune to critical hits, poison, and sneak attacks.</p>
<p>At 20th level, aeon eidolons gain the ability to cast <Link to="/spell/moment_of_prescience">moment of prescience</Link> (CL 20th) as a spell-like ability three times per day.</p>
</>};
const _agathion = {title: "Agathion", jsx: <><h2 id="eidolon-agathion-agathion">Agathion</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 29</Link><br/>Patient and enlightened liaisons of the good-aligned Outer Planes, <Link to="/family/agathion">agathion</Link> eidolons seek to vanquish evil and protect that which is good. Agathion eidolons always have aspects of a single animal or creature, rather than a hodgepodge of several. Though they have patience for summoners with unorthodox methods and even those who stray from the path of good, they will not brook their powers being used for evil ends. An agathion eidolon seeks to bring its summoner closer to its own enlightenment.</p>
<p><strong>Alignment</strong> Neutral good.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]) or quadruped (limbs [legs, 2], <Link to="/unchevolution/bite">bite</Link>).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, agathion eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (electricity) evolution. They also gain a +4 bonus on saving throws against poison and petrification.</p>
<p>At 4th level, agathion eidolons gain cold resistance 10 and sonic resistance 10.</p>
<p>At 8th level, agathion eidolons gain <Link to="/ability/lay_on_hands">lay on hands</Link> as paladins with levels equal to their Hit Dice.</p>
<p>At 12th level, agathion eidolons gain DR 5/evil. They also gain immunity to petrification and the truespeech ability (see the <Link to="/subtype/agathion">agathion creature subtype</Link>).</p>
<p>At 16th level, agathion eidolons lose the resistance (electricity) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (electricity) evolution. They also gain the agathion's <em>speak with animals</em> ability (see the agathion creature subtype).</p>
<p>At 20th level, agathion eidolons gain <Link to="/spell/detect_thoughts">detect thoughts</Link> as a spell-like ability at will and also increase their damage reduction to DR 10/evil.</p>
</>};
const _ancestor = {title: "Ancestor", jsx: <><h2 id="eidolon-ancestor-ancestor">Ancestor</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast pg. 31</Link><br/>Whether created by bonding with the soul of a petitioner that was the summoner's ancestor in life or calling upon the impressions of such a soul left behind on the Ethereal Plane or the Akashic Record, ancestor eidolons are outsiders cast in the mold of mortals, and exhibit extraordinary skill and talent. They usually appear as idealized versions of the bodies they possessed while still alive, but distinctive and proud. Ancestor eidolons lend whatever aid they can to their summoner, who typically has some form of familial connection with the eidolon, be it by blood, honor, or devotion.</p>
<p><strong>Alignment</strong> Any. Ancestor eidolons don't have any alignment subtypes.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]).</p>
<p><strong>Base Evolutions</strong> At 1st level, an ancestor eidolon gains all of the racial traits associated with its summoner's race; a summoner who isn't a 0-Hit Die creature must choose one 0-Hit Die race of his choice. For any effect dependent on class level, an ancestor eidolon uses its total Hit Dice instead (such as with the human's skilled racial trait). An ancestor eidolon counts as a creature of its chosen race's type and subtype for all effects, except for the purpose of meeting feat prerequisite requirements. An ancestor eidolon gains only the standard racial traits of its race; it cannot select alternate racial traits.</p>
<p>At 4th level, the ancestor eidolon chooses one of the following simple class templates: <Link to="/template/fighter">fighter</Link>, <Link to="/template/rogue">rogue</Link>, or <Link to="/template/sorcerer">sorcerer</Link>. It gains the abilities noted under the template's quick rules as if it were a creature with 1 Hit Die. The eidolon does not gain any abilities that a character with 1 level in the class associated with the chosen template wouldn't have. For instance, a 1-HD creature with the rogue simple template would normally gain the evasion and uncanny dodge abilities, but an ancestor eidolon that chooses the rogue simple template does not gain these abilities since a 1st-level rogue would not have evasion or uncanny dodge.</p>
<p>At 8th level, the ancestor eidolon gains the <Link to="/unchevolution/skilled">skilled</Link> evolution with two skills that are on the list of class skills of the class associated with the eidolon's chosen simple class template.</p>
<p>At 12th level, the ancestor eidolon gains the abilities noted under its chosen simple class templates as if it were a creature with 5 Hit Dice, rather than 1 Hit Die. The eidolon doesn't gain any abilities that a character with 5 levels in the class associated with the chosen template wouldn't have.</p>
<p>At 16th level, the ancestor eidolon gains a bonus feat, chosen from the following list: <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/great_fortitude">Great Fortitude</Link>, <Link to="/feat/improved_initiative">Improved Initiative</Link>, <Link to="/feat/iron_will">Iron Will</Link>, <Link to="/feat/lightning_reflexes">Lightning Reflexes</Link>, <Link to="/feat/toughness">Toughness</Link>, or any feat that lists the eidolon's chosen race as a prerequisite. The eidolon must meet all of the chosen feat's prerequisites.</p>
<p>At 20th level, the ancestor eidolon gains the abilities noted under its chosen simple class templates as if it were a creature with 10 Hit Dice, rather than 5 Hit Dice. The eidolon doesn't gain any abilities that a character with 10 levels in the class associated with the chosen template wouldn't have.</p>
</>};
const _angel = {title: "Angel", jsx: <><h2 id="eidolon-angel-angel">Angel</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 30</Link><br/>Hailing from the higher planes, <Link to="/family/angel">angel</Link> eidolons are creatures of exquisite beauty. They usually appear in idealized humanoid forms, with smooth skin, shining hair, and bright eyes. Angel eidolons are impeccably honorable, trustworthy, and diplomatic, but they do not shy away from confrontation when facing off against evil and its minions.</p>
<p><strong>Alignment</strong> Any good.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], slam).</p>
<p><strong>Base Evolutions</strong> At 1st level, angel eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (acid) and resistance (cold) evolutions. They also gain a +4 bonus on saving throws against poison.</p>
<p>At 4th level, angel eidolons gain electricity resistance 10 and fire resistance 10.</p>
<p>At 8th level, angel eidolons grow large, feathery wings, gaining the <Link to="/unchevolution/flight">flight</Link> evolution.</p>
<p>At 12th level, angel eidolons gain DR 5/evil. They also gain immunity to petrification and the truespeech ability (see the <Link to="/subtype/angel">angel creature subtype</Link>).</p>
<p>At 16th level, angel eidolons lose the resistance (acid) and resistance (cold) evolutions, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (acid) and immunity (cold) evolutions.</p>
<p>At 20th level, angel eidolons gain the protective aura ability (see the angel creature subtype).</p>
</>};
const _archon = {title: "Archon", jsx: <><h2 id="eidolon-archon-archon">Archon</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 30</Link><br/>Summoned from heaven, <Link to="/family/archon">archon</Link> eidolons are the embodiments of righteousness. They often take on powerful, graceful forms, rippling with muscles but refined in their movements. Archon eidolons are totally dedicated to the cause of good, and have little patience for those who violate their oaths and ideals - including the summoner who called them. Archons will do whatever it takes to stop the advance of evil and protect the innocent.</p>
<p><strong>Alignment</strong> Lawful good.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, archon eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (electricity) evolution and the <Link to="/unchevolution/skilled">skilled</Link> (Intimidate) evolution. They also gain a +4 bonus on saving throws against poison.</p>
<p>At 4th level, archon eidolons add 1 point to their evolution pools.</p>
<p>At 8th level, archon eidolons gain the <Link to="/unchevolution/ability_increase">ability increase</Link> evolution, applied to an ability score the summoner chooses.</p>
<p>At 12th level, archon eidolons gain DR 5/evil. They also gain immunity to petrification and the truespeech ability (see the <Link to="/subtype/archon">archon creature subtype</Link>).</p>
<p>At 16th level, archon eidolons lose the resistance (electricity) evolution and skilled (Intimidate) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (electricity) evolution. In addition, they gain the aura of menace ability (see the archon creature subtype).</p>
<p>At 20th level, archon eidolons gain the ability to use <Link to="/spell/greater_teleport">greater teleport</Link> at will, as the spell (caster level 14th), except they can teleport only themselves and up to 50 pounds of carried objects.</p>
</>};
const _astral = {title: "Astral", jsx: <><h2 id="eidolon-astral-astral">Astral</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 24</Link><br/>While some resemble ouroboroses, most astral eidolons are spun from raw thought or the husks of Astral travelers whose silver cords broke.</p>
<p><strong>Alignment</strong> Neutral.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>) or serpentine (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/magic_attacks">magic attacks</Link>, <Link to="/unchevolution/reach">reach</Link> [bite], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, astral eidolons gain immunity to aging as well as a +4 bonus on saving throws against curses, diseases, and poisons. A summoner's class level is halved for the purpose of determining the rate at which his astral eidolon's Strength and Dexterity increase.</p>
<p>At 4th level, astral eidolons gain the ability to augment their masters' summoning abilities three times per day. To do so, the astral eidolon must ready an action to meld with a summoned creature. The summoner can use his summon monster spell-like ability or cast a <Link to="/spell/summon_monster">summon monster</Link> spell while the astral eidolon is summoned and readied to activate this ability. The eidolon physically melds with one summoned creature as it appears, during which time the eidolon cannot be harmed or take actions of its own except to end the effect as a standard action. The eidolon must be adjacent to or share the space where the summoned creature will appear. The effect ends either when the spell ends, when the summoned creature is slain or dismissed, or when either the summoner or eidolon ends the effect as a standard action, after which the summoned creature disappears and the eidolon appears in the creature's space and is <Link to="/misc/staggered">staggered</Link> until the beginning of the summoner's next turn.</p>
<p>When melded with a summoned creature, the eidolon grants the summoned creature one or more evolutions the eidolon has (maximum 1 point worth of evolutions for every 3 Hit Dice the eidolon has) and a number of <Link to="/rule/temporary_hit_points">temporary hit points</Link> equal to 1d8 plus the eidolon's number of Hit Dice. The summoned creature must conform to any limitations of the evolution (for example, it must have wings in order to gain the <Link to="/unchevolution/wing_buffet">wing buffet</Link> evolution). Furthermore, the summoned creature cannot gain more than one natural attack in this way, though it can replace the damage of its natural weapons with that dealt by the evolution, provided the natural weapons are similar. For effects dependent on Hit Dice, use the eidolon's Hit Dice.</p>
<p>At 8th level, astral eidolons gain the <Link to="/unchevolution/flight">flight</Link> evolution (using magic) with a speed equal to their base speed.</p>
<p>At 12th level, astral eidolons gain the ability to augment their master's summoning two additional times per day. When the eidolon melds with a summoned creature, that creature also gains the eidolon's evasion and devotion abilities.</p>
<p>At 16th level, astral eidolons gain immunity to curses, diseases, and poisons. They also increase by 50% the number of evolution points their summoners can divert using the aspect and greater aspect abilities. If the summoner lacks the aspect ability, he gains this ability but can divert only 1 evolution point. The summoner no longer takes penalties to his ability scores for <Link to="/rule/aging">aging</Link>, cannot be magically aged, and does not age retroactively when leaving a plane with the <Link to="/rule/time_traits">timeless planar trait</Link>. Ability score bonuses from age still accrue, and the summoner still dies of old age when his time is up.</p>
<p>At 20th level, astral eidolons can simultaneously meld with each creature summoned by the summoner's summon monster spell-like ability or summon monster spells, and the eidolon does not reappear automatically until each of the creatures is slain. Alternatively, the eidolon can meld with one summoned creature without disappearing, though the eidolon is staggered until the effect ends.</p>
</>};
const _azata = {title: "Azata", jsx: <><h2 id="eidolon-azata-azata">Azata</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 30</Link><br/>Embodiments of the untamable beauty and noble passion of Elysium, <Link to="/family/azata">azata</Link> eidolons have wild and beautiful features. They often take graceful forms reminiscent of elves or fey, but they occasionally appear like lillends, with serpentine tails. Azata eidolons are flighty and independent, and they often have their own ideas about how to defeat evil or have a good time. Thus, an azata eidolon is likely to balk if its summoner commands it to perform offensive or nefarious actions. On the other hand, an azata eidolon in sync with its summoner is a passionate and devoted companion.</p>
<p><strong>Alignment</strong> Chaotic good.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]) or serpentine (limbs [arms], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, azata eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (electricity) evolution and the 4-point <Link to="/unchevolution/weapon_training">weapon training</Link> evolution (proficiency in martial weapons).</p>
<p>At 4th level, azata eidolons gain cold resistance 10 and fire resistance 10.</p>
<p>At 8th level, azata eidolons grow large, feathery wings, gaining the <Link to="/unchevolution/flight">flight</Link> evolution.</p>
<p>At 12th level, azata eidolons gain DR 5/evil. They also gain immunity to petrification and the truespeech ability (see the <Link to="/subtype/azata">azata creature subtype</Link>).</p>
<p>At 16th level, azata eidolons lose the resistance (electricity) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (electricity) evolution. They also gain the <Link to="/unchevolution/ability_increase">ability increase</Link> evolution, applied to an ability score of the summoner's choice.</p>
<p>At 20th level, an azata eidolon gains the ability to switch between its normal form and an energy form as a standard action. In its energy form, an azata eidolon is incorporeal and doubles its fly speed, but it can't make natural or manufactured weapon attacks; it can, however, activate any spell-like ability evolutions it possesses.</p>
</>};
const _daemon = {title: "Daemon", jsx: <><h2 id="eidolon-daemon-daemon">Daemon</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 31</Link><br/>The agents of horrible deaths, <Link to="/family/daemon">daemon</Link> eidolons desire the utter annihilation of all things. Their forms vary wildly depending on which type of death they embody, and daemon eidolons sometimes represent a more obscure kind of death than the most famous daemons. Daemon eidolons wish to sow death and misery through a variety of means. Most are capable of seeing the big picture, and will obediently follow even a neutral summoner. Ending lives is a typical part of an adventurer's career, so following along with a summoner gives a daemon eidolon many opportunities to gather mortal soul energy for its own dark and inscrutable purposes.</p>
<p><strong>Alignment</strong> Neutral evil.</p>
<p><strong>Base Form</strong> Aberrant (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/tentacle_mass">tentacle mass</Link>), Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]), quadruped (limbs [legs, 2], bite), or serpentine (bite, <Link to="/unchevolution/reach">reach</Link> [bite], reach [sting], <Link to="/unchevolution/sting">sting</Link>, <Link to="/unchevolution/tail">tail</Link>).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, daemon eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (acid) evolution as well as a +4 bonus on saving throws against death effects, disease, and poison.</p>
<p>At 4th level, daemon eidolons gain cold resistance 10, electricity resistance 10, and fire resistance 10.</p>
<p>At 8th level, daemon eidolons add 1 point to their evolution pools.</p>
<p>At 12th level, daemon eidolons gain DR 5/good. They also gain immunity to death effects, disease, and poison.</p>
<p>At 16th level, daemon eidolons lose the resistance (acid) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (acid) evolution. They also gain <Link to="/umr/telepathy">telepathy</Link>.</p>
<p>At 20th level, as a standard action, a daemon eidolon can devour a portion of the soul of a dying creature or a creature that died no earlier than 1 round ago. This kills the creature and provides the daemon eidolon a profane bonus on attack rolls, saving throws, and skill checks for 24 hours. The bonus is equal to +1 per 5 Hit Dice the slain creature possessed. A creature whose soul was devoured in this way requires <Link to="/spell/resurrection">resurrection</Link> or more powerful magic to return from the dead.</p>
</>};
const _deepwater = {title: "Deepwater", jsx: <><h2 id="eidolon-deepwater-deepwater">Deepwater</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_sea">Blood of the Sea pg. 23</Link><br/>The vast, lightless reaches of the sea are home to creatures of unimaginable power with connections to dangerous planes. A few rare summoners attempt to conjure forth eidolons from these cold, alien depths, drawing forth utterly inhuman allies with squirming tentacles and gnashing beaks. Although these eidolons may superficially resemble primeval beasts such as <Link to="/monster/aboleth">aboleths</Link>, <Link to="/monster/kraken">krakens</Link>, or monstrous squids or eels - if they resemble any previously encountered deep-sea life-form at all - they are outsiders like any other eidolon for the purposes of spells and effects that affect them.</p>
<p><strong>Alignment</strong> Chaotic evil, chaotic neutral, neutral, or neutral evil.</p>
<p><strong>Base Form</strong> Serpentine (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/grab">grab</Link> [tail slap], <Link to="/unchevolution/reach">reach</Link> [tail slap], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, deepwater eidolons gain the <Link to="/unchevolution/gills">gills</Link>, <Link to="/unchevolution/resistance">resistance</Link> (cold), and <Link to="/unchevolution/swim">swim</Link> evolutions.</p>
<p>At 4th level, deepwater eidolons gain the <Link to="/umr/jet">jet</Link> ability at a speed of 200 feet and increase the range of their darkvision to 120 feet.</p>
<p>At 8th level, deepwater eidolons gain the <Link to="/unchevolution/poison">poison</Link> evolution for all tail slap and tentacle attacks, although the poison can be used only once per round. The summoner can spend 2 evolution points to make this poison deal <Link to="/rule/constitution_damage">Constitution damage</Link> instead of Strength damage, as normal for the poison evolution.</p>
<p>At 12th level, deepwater eidolons gain DR 5/magic. They also gain the <Link to="/unchevolution/rend">rend</Link> evolution for tentacle attacks rather than claw attacks.</p>
<p>At 16th level, deepwater eidolons lose the resistance (cold) evolution and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (cold) evolution.</p>
<p>At 20th level, deepwater eidolons gain constant <Link to="/spell/freedom_of_movement">freedom of movement</Link> and <Link to="/umr/fast_healing">fast healing</Link> 5.</p>
</>};
const _demon = {title: "Demon", jsx: <><h2 id="eidolon-demon-demon">Demon</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 31</Link><br/>Raw destruction given material substance, <Link to="/family/demon">demon</Link> eidolons form out of the Abyss's stew of soul energy, leading some scholars to speculate that the summoner's arts are related to the magical tampering that gave rise to the first demons. Demon eidolons revel in causing destruction and inflicting suffering, and they will do so for their summoners without question, taking pleasure in whatever havoc they can create. For a demon eidolon, the means justify the ends.</p>
<p><strong>Alignment</strong> Chaotic evil.</p>
<p><strong>Base Form</strong> Aberrant (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/tentacle_mass">tentacle mass</Link>), Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]), quadruped (limbs [legs, 2], bite), or serpentine (bite, <Link to="/unchevolution/improved_damage">improved damage</Link> [bite], <Link to="/unchevolution/reach">reach</Link> [bite], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, demon eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (electricity) and resistance (fire) evolutions as well as a +4 bonus on saving throws against poison.</p>
<p>At 4th level, demon eidolons gain acid resistance 10 and cold resistance 10.</p>
<p>At 8th level, demon eidolons lose the +4 bonus on saving throws against poison and gain immunity to poison. They also add 1 point to their evolution pools.</p>
<p>At 12th level, demon eidolons gain DR 5/good. They also gain the <Link to="/unchevolution/ability_increase">ability increase</Link> evolution in an ability score of the summoner's choice.</p>
<p>At 16th level, demon eidolons lose the resistance (electricity) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (electricity) evolution. They also gain <Link to="/umr/telepathy">telepathy</Link>.</p>
<p>At 20th level, demon eidolons gain <Link to="/spell/true_seeing">true seeing</Link> as a constant spell-like ability.</p>
</>};
const _devil = {title: "Devil", jsx: <><h2 id="eidolon-devil-devil">Devil</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 32</Link><br/>Corruptors, tempters, and despoilers, <Link to="/family/devil">devil</Link> eidolons often serve their summoners obediently and efficiently, all in a long-term attempt to damn the summoner's soul to the deepest depths of Hell. While some types of devils have truly unusual forms, devil eidolons have found that the more traditional bipedal form allows them to build up a strong rapport with their summoners - and consequently to corrupt them - more easily than if they possessed a more monstrous appearance.</p>
<p><strong>Alignment</strong> Lawful evil.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, devil eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (fire) evolution and the <Link to="/unchevolution/skilled">skilled</Link> (Bluff) evolution. They also gain a +4 bonus on saving throws against poison.</p>
<p>At 4th level, devil eidolons gain acid resistance 10 and cold resistance 10.</p>
<p>At 8th level, devil eidolons gain the skilled (Diplomacy) evolution and gain immunity to poison.</p>
<p>At 12th level, devil eidolons gain DR 5/good. They also gain see in darkness (see the <Link to="/subtype/devil">devil creature subtype</Link>).</p>
<p>At 16th level, devil eidolons lose the resistance (fire) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (fire) evolution. They also gain <Link to="/umr/telepathy">telepathy</Link>.</p>
<p>At 20th level, devil eidolons gain regeneration 5 (good weapons, good spells). They are still banished to Hell as normal for eidolons if they take enough damage.</p>
</>};
const _div = {title: "Div", jsx: <><h2 id="eidolon-div-div">Div</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 32</Link><br/>Formed of hatred and spite, <Link to="/family/div">div</Link> eidolons seek to despoil and ruin all things beautiful and joyous. Div eidolons particularly resent having mortal masters, and seek to doom their summoners to existences full of suffering and loss. Each div eidolon has a unique compulsion it must follow - usually something similar to the <Link to="/monster/doru">doru's</Link> obsession with secrets - that leads it to bargain its loyalty for something the summoner provides. The div's summoner uses his eidolon's compulsion to entrap and control the eidolon. Still, div eidolons never fully give in, and continue to plot ways they might corrupt that which their masters hold dearest.</p>
<p><strong>Alignment</strong> Neutral evil.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, div eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (fire) evolution. They also gain a +4 bonus on saving throws against poison.</p>
<p>At 4th level, div eidolons gain acid resistance 10 and electricity resistance 10.</p>
<p>At 8th level, div eidolons add 1 point to their evolution pools and immunity to poison.</p>
<p>At 12th level, div eidolons gain DR 5/good. They also gain see in darkness (see the <Link to="/subtype/div">div creature subtype</Link>).</p>
<p>At 16th level, div eidolons lose the resistance (fire) evolution, and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (fire) evolution. They also gain <Link to="/umr/telepathy">telepathy</Link>.</p>
<p>At 20th level, div eidolons gain the ability to use <Link to="/spell/greater_teleport">greater teleport</Link> at will, as per the spell (caster level 14th), except they can teleport only themselves and up to 50 pounds of carried objects.</p>
</>};
const _elemental = {title: "Elemental", jsx: <><h2 id="eidolon-elemental-elemental">Elemental</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 33</Link><br/>Pulled in from one of the four elemental planes, these eidolons are linked to one of the four elements: air, earth, fire, or water. Generally, an <Link to="/family/elemental">elemental</Link> eidolon appears as a creature made entirely of one element, but there is some variation. Elemental eidolons are decidedly moderate in their views and actions. They tend to avoid the conflicts of others when they can and seek to maintain balance. The only exception is when facing off against emissaries of their opposing elements, which they hate utterly.</p>
<p><strong>Alignment</strong> Neutral.</p>
<p><strong>Base Form</strong> Aberrant (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/tentacle_mass">tentacle mass</Link>), Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>), quadruped (limbs [legs, 2], bite), or serpentine (bite, <Link to="/unchevolution/improved_natural_armor">improved natural armor</Link>, <Link to="/unchevolution/reach">reach</Link> [bite], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> The base evolutions of an elemental eidolon depend entirely on its chosen element. When first summoning an elemental eidolon, the summoner must select air, earth, fire, or water. Once made, this choice cannot be changed. The eidolon gains the following evolutions and abilities, which can vary depending on its element.</p>
<p>At 1st level, all elemental eidolons gain immunity to paralysis and sleep. In addition, air elemental eidolons gain the <Link to="/unchevolution/immunity">immunity</Link> (electricity) evolution. Earth elemental eidolons gain the immunity (acid) evolution. Fire elemental eidolons gain the immunity (fire) evolution. Water elemental eidolons gain the immunity (cold) evolution.</p>
<p>At 4th level, all elemental eidolons add 1 point to their evolution pools.</p>
<p>At 8th level, air elemental eidolons gain the <Link to="/unchevolution/flight">flight</Link> evolution (using magic) with a speed equal to their base speed. Earth elemental eidolons gain the <Link to="/unchevolution/burrow">burrow</Link> evolution. Fire elemental eidolons increase their base speed by 20 feet. Water elemental eidolons gain the <Link to="/unchevolution/swim">swim</Link> evolution twice, gaining a swim speed equal to their base speed + 20 feet. They also gain the <Link to="/unchevolution/gills">gills</Link> evolution, which allows them to breathe underwater.</p>
<p>At 12th level, all elemental eidolons gain immunity to bleed, poison, and stun. In addition, they can no longer be flanked.</p>
<p>At 16th level, all elemental eidolons gain immunity to critical hits and do not take additional damage from precision-based attacks, such as sneak attack.</p>
<p>At 20th level, an air elemental eidolon gains the <Link to="/umr/whirlwind">whirlwind</Link> ability, with a maximum height of 15 feet (30 feet for a Large air elemental) and dealing 1d6 points of damage (1d8 for a Large air elemental). Earth elemental eidolons gain the earth mastery ability of an <Link to="/monster/earth_elemental">earth elemental</Link> and DR 5/-. Fire elemental eidolons gain the <Link to="/unchevolution/energy_attacks">energy attacks</Link> (fire) evolution and the <Link to="/umr/burn">burn</Link> ability. Water elemental eidolons gain the drench and vortex abilities of a <Link to="/monster/water_elemental">water elemental</Link>. The vortex ability works as the air elemental eidolon's whirlwind ability (except as noted in the vortex ability's description).</p>
</>};
const _genie = {title: "Genie", jsx: <><h2 id="eidolon-genie-genie">Genie</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 27</Link><br/>Genies are elemental beings that take humanoid forms, and <Link to="/family/genie">genie</Link> eidolons often vacillate between humble kowtowing and biting observations about the summoner's foibles that make the eidolon look superior.</p>
<p><strong>Alignment</strong> Chaotic good, chaotic neutral, lawful evil, lawful neutral, or neutral.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, genie eidolons gain the 4-point <Link to="/unchevolution/weapon_training">weapon training</Link> evolution as well as the <Link to="/unchevolution/resistance">resistance</Link> evolution for any one energy type.</p>
<p>At 4th level, genie eidolons gain the ability to grow in size twice per day as a full-round action. This grants them the <Link to="/unchevolution/large">large</Link> evolution for 1 round per Hit Die they have, increases the size of their equipment for the duration, and does not stack with other size-changing effects. Genie eidolons who later purchase the large evolution lose this ability, but they add 1 point to their evolution pools.</p>
<p>At 8th level, genie eidolons gain either the <Link to="/unchevolution/flight">flight</Link> evolution (using magic) with a speed equal to their base speed; the <Link to="/unchevolution/burrow">burrow</Link> evolution; or the <Link to="/unchevolution/gills">gills</Link> evolution, plus the <Link to="/unchevolution/swim">swim</Link> evolution twice, gaining a swim speed equal to their base speed + 20 feet.</p>
<p>At 12th level, genie eidolons lose the resistance evolution gained at 1st level and instead gain the <Link to="/unchevolution/immunity">immunity</Link> evolution to the selected energy type. They can also cast <Link to="/spell/plane_shift">plane shift</Link> as a spell-like ability once per day (CL 12th), but only to transport willing targets to the Astral Plane, Elemental Planes, or Material Plane.</p>
<p>At 16th level, once per day as a standard action, genie eidolons can cast <Link to="/spell/cleanse">cleanse</Link> or <Link to="/spell/greater_evolution_surge">greater evolution surge</Link> (CL 16th) on themselves as a spell-like ability, but only in response to their masters' spoken wish (such as "I wish you were stronger"). The master can make such a wish as a free action.</p>
<p>At 20th level, genie eidolons gain the 20th-level base evolutions of an <Link to="/eidolon/elemental">elemental</Link> eidolon of any one element.</p>
</>};
const _inevitable = {title: "Inevitable", jsx: <><h2 id="eidolon-inevitable-inevitable">Inevitable</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 33</Link><br/>Implacable and ceaseless in their fight against chaos and those who break natural laws, <Link to="/family/inevitable">inevitables</Link> make loyal, if literal-minded, companions for lawful summoners. Summoners of inevitables generally get along well with axiomites, who share their understanding of the process of forging and modifying an inevitable. Inevitable eidolons appear as a mixture between clockwork constructs and idealized humanoid statues.</p>
<p><strong>Alignment</strong> Lawful neutral.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, inevitable eidolons count as both constructs and outsiders for the purpose of effects such as the <Link to="/magic-enh/bane">bane</Link> weapon special ability and the <Link to="/ability/favored_enemy">favored enemy</Link> class feature. They gain a +4 bonus on saving throws against death effects, disease, necromancy effects, paralysis, poison, sleep, and stun.</p>
<p>At 4th level, inevitable eidolons gain a +4 bonus on saving throws against mind-affecting effects and immunity to nonlethal damage, fatigue, and exhaustion.</p>
<p>At 8th level, inevitable eidolons gain immunity to death effects, disease, and poison.</p>
<p>At 12th level, inevitable eidolons gain DR 5/chaotic. They also gain immunity to sleep, as well as the true speech ability (see the <Link to="/subtype/inevitable">inevitable creature subtype</Link>).</p>
<p>At 16th level, inevitable eidolons lose the +4 bonus on saving throws against necromancy effects and gain immunity to ability damage, ability drain, energy drain, and necromancy effects.</p>
<p>At 20th level, inevitable eidolons gain immunity to paralysis, sleep, stun, and any effect that requires a Fortitude save (unless the effect also works on objects).</p>
</>};
const _kami = {title: "Kami", jsx: <><h2 id="eidolon-kami-kami">Kami</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 18</Link><br/><Link to="/family/kami">Kami</Link> eidolons are spirits of nature bound to an unchained summoner. They seek to protect their wards, but because of their summoner's bond, they have more flexibility choosing their wards than most of their kind.</p>
<p><strong>Alignment</strong> Any non-evil. Kami eidolons do not have an alignment subtype, instead having the native subtype.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, a kami eidolon gains the <Link to="/unchevolution/resistance">resistance</Link> (fire) evolution and the 4-point <Link to="/unchevolution/weapon_training">weapon training</Link> evolution (proficiency in martial weapons).</p>
<p>At 4th level, a kami eidolon gains acid resistance 10 and cold resistance 10.</p>
<p>At 8th level, a kami eidolon can declare a ward once per day as a standard action. Its ward must be an object, a plant, or a creature with an Intelligence score of 2 or less, and the ward maintains the designation for 1 hour. So long as a kami eidolon is within 60 feet of its ward, it and its ward gain a +2 sacred bonus on saving throws.</p>
<p>At 12th level, a kami eidolon gains the 4-point version of the <Link to="/unchevolution/fast_healing">fast healing</Link> evolution and the merge with ward ability (see the <Link to="/subtype/kami">kami subtype</Link>. A kami eidolon automatically emerges from its ward if they are merged when that object or creature ceases to be the eidolon's ward.</p>
<p>At 16th level, kami eidolons are immune to bleed, mind-affecting, petrification, and polymorph effects.</p>
<p>At 20th level, a kami eidolon increases the fast healing from its fast healing evolution by 2 points whenever it is within 30 feet of its ward; while the kami is merged with its ward, the ward gains the same amount of fast healing.</p>
</>};
const _kyton = {title: "Kyton", jsx: <><h2 id="eidolon-kyton-kyton">Kyton</h2>
<p><strong>Sources</strong> <Link to="/source/curse_of_the_crimson_throne">Curse of the Crimson Throne pg. 431</Link><br/>Scholars of the exquisiteness of agony and explorers of the limitations of the flesh, <Link to="/family/kyton">kytons</Link> understand the mortal form is a blank canvas aching for transformation. They appear as humanoids, save that they are covered in piercings, draped with chains, and bear grisly body modifications. Kyton eidolons gain access to the <Link to="/unchevolution/tentacle">tentacle</Link> and <Link to="/unchevolution/web">web</Link> evolutions, but kyton eidolon tentacles and webs always appear as animated chains.</p>
<p><strong>Alignment</strong> Lawful evil.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/improved_natural_armor">improved natural armor</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]).</p>
<p><strong>Base Evolutions</strong> At 1st level, kyton eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (cold) and skilled (Heal) evolutions. They also gain proficiency with the spiked chain.</p>
<p>At 4th level, a kyton eidolon adds 1 point to its evolution pool.</p>
<p>At 8th level, a kyton eidolon gains an unnerving gaze that manipulates the perceptions of those who look upon it. Unlike typical gaze weapons, a kyton eidolon's unnerving gaze can affect only one creature per round when the kyton directs its gaze at the target on its turn as a free action. An unnerving gaze has a range of 30 feet, and can be negated by a successful Will save. Any creature that fails the save becomes <Link to="/misc/sickened">sickened</Link> by the kyton's grisly modifications for 1 round. A kyton eidolon is immune to the unnerving gazes of other kytons, and the kyton's summoner is immune to its unnerving gaze. This is a mind-affecting fear effect. The save DC is Charisma-based.</p>
<p>At 12th level, a kyton eidolon gains DR 5/good. The effects of a kyton eidolon's unnerving gaze now persist for 1d3 rounds, and as a free action, a kytons can target up to two creatures per round with its gaze on its turns.</p>
<p>At 16th level, a kyton eidolon loses the resistance (cold) evolution, and gains the <Link to="/unchevolution/immunity">immunity</Link> (cold) evolution in its place. The effects of a kyton eidolon's unnerving gaze now <Link to="/misc/stagger">stagger</Link> the target for 1 round, and as a free action, a kyton eidolon can target up to three creatures per round with its gaze.</p>
<p>At 20th level, a kyton eidolon gains <Link to="/umr/regeneration">regeneration</Link> 5 (good weapons, good spells). It is still banished to the Shadow Plane as normal for an eidolon if it takes enough damage.</p>
</>};
const _plant = {title: "Plant", jsx: <><h2 id="eidolon-plant-plant">Plant</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 95</Link><br/>Plant eidolons consist of vegetable matter infused with raw natural spiritual power.</p>
<p><strong>Alignment</strong> Any. Plant eidolons don't have alignment subtypes.</p>
<p><strong>Base Form</strong> Cactus (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/sting">sting</Link>), conifer (<Link to="/unchevolution/claws">claws</Link>, limbs [arms], limbs [legs]), fungus (<Link to="/unchevolution/bite">bite</Link>, limbs [arms], limbs [legs]), leaf (limbs [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>), seaweed (limbs [arms], slam, <Link to="/unchevolution/swim">swim</Link> [2]).</p>
<p><strong>Base Evolutions</strong> At 1st level, plant eidolons gain low-light vision as well as the <Link to="/unchevolution/resistance">resistance</Link> (electricity) and resistance (sonic) evolutions.</p>
<p>At 4th level, plant eidolons gain constant <Link to="/spell/pass_without_trace">pass without trace</Link> and they can change shape into plants of the size category corresponding to their base form with results similar to <Link to="/spell/tree_shape">tree shape</Link>.</p>
<p>At 8th level, plant eidolons gain the ability to use <Link to="/spell/speak_with_plants">speak with plants</Link> for 1 minute per Hit Die per day with any plants related to the eidolon's base form. These minutes need not be consecutive.</p>
<p>At 12th level, plant eidolons gain immunity to paralysis, poison, sleep, and stun.</p>
<p>At 16th level, plant eidolons gain the ability to use <Link to="/spell/commune_with_nature">commune with nature</Link> once per day and can use their <em>speak with plants</em> ability at will. At 20th level, plant eidolons gain a +8 resistance bonus on saving throws against mind-affecting effects. They lose their resistance (electricity) and resistance (sonic) evolutions and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (electricity) and immunity (sonic) evolutions.</p>
</>};
const _protean = {title: "Protean", jsx: <><h2 id="eidolon-protean-protean">Protean</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 33</Link><br/>Serpentine beings of pure chaos, <Link to="/family/protean">proteans</Link> seek to reshape reality. Protean eidolons appreciate creative summoners who often rebuild their forms and make liberal use of the <Link to="/spell/transmogrify">transmogrify</Link> spell. Beyond that, protean eidolons are happy to work with their summoners for any purpose, though they are quick to remind their summoners that while they have a mutually beneficial relationship, they are not servants.</p>
<p><strong>Alignment</strong> Chaotic neutral.</p>
<p><strong>Base Form</strong> Serpentine (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/grab">grab</Link> [tail slap], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, protean eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (acid) evolution as well as the <em>grab</em> evolution, tied to an attack type of the summoner's choice. Whenever the summoner changes the protean eidolon's evolutions, he can also change the attack type for grab.</p>
<p>At 4th level, protean eidolons gain electricity resistance 10 and sonic resistance 10.</p>
<p>At 8th level, protean eidolons gain the <Link to="/unchevolution/constrict">constrict</Link> evolution.</p>
<p>At 12th level, protean eidolons gain DR 5/lawful. They also gain the <Link to="/unchevolution/blindsense">blindsense</Link> evolution and the ability to fly without wings with perfect maneuverability, as the <Link to="/unchevolution/flight">flight</Link> evolution with 4 points spent.</p>
<p>At 16th level, protean eidolons lose the resistance (acid) evolution and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (acid) evolution. They also gain the amorphous anatomy ability (see the <Link to="/subtype/protean">protean creature subtype</Link>).</p>
<p>At 20th level, protean eidolons gain constant <Link to="/spell/freedom_of_movement">freedom of movement</Link> and the protean version of the change shape (greater polymorph) ability (see the protean creature subtype).</p>
</>};
const _psychopomp = {title: "Psychopomp", jsx: <><h2 id="eidolon-psychopomp-psychopomp">Psychopomp</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 34</Link><br/>Stewards, chroniclers, and guides of all things that die, <Link to="/family/psychopomp">psychopomps</Link> make dispassionate yet loyal eidolons. When they deal with the world of mortals, psychopomp eidolons nearly always wear masks. They do not tolerate summoners who traffic with daemons, undead, and other entities that interfere with the transmigration of souls, but otherwise they are comfortable with most actions on the summoner's part. When the summoner dies, a psychopomp eidolon personally escorts him to the afterlife and serves as an expert witness when it is time for him to be judged.</p>
<p><strong>Alignment</strong> Neutral.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>), quadruped (<Link to="/unchevolution/bite">bite</Link>, limbs [legs, 2]), or serpentine (bite, <Link to="/unchevolution/pull">pull</Link> [bite], <Link to="/unchevolution/reach">reach</Link> [bite], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> Starting at 1st level, psychopomp eidolons gain immunity to death effects, disease, and poison.</p>
<p>At 4th level, psychopomp eidolons gain cold resistance 10 and electricity resistance 10.</p>
<p>At 8th level, psychopomp eidolons gain the spirit touch ability (see the <Link to="/subtype/psychopomp">psychopomp creature subtype</Link>) and add 1 point to their evolution pools.</p>
<p>At 12th level, psychopomp eidolons gain DR 5/adamantine. They also gain the spiritsense ability (see the psychopomp creature subtype).</p>
<p>At 16th level, psychopomp eidolons gain the <Link to="/unchevolution/ability_increase">ability increase</Link> evolution, applied to an ability score of the summoner's choice. They also gain the ability to cast <Link to="/spell/invisibility">invisibility</Link> (self only) as a spell-like ability at will.</p>
<p>At 20th level, psychopomp eidolons increase their damage reduction to 10/adamantine and gain the <Link to="/unchevolution/immunity">immunity</Link> (cold) and immunity (electricity) evolutions.</p>
</>};
const _radiant = {title: "Radiant", jsx: <><h2 id="eidolon-radiant-radiant">Radiant</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 25</Link><br/>Practically glowing with the Positive Energy Plane's potential, radiant eidolons make for passionate, if judgmental, companions that often have avian features.</p>
<p><strong>Alignment</strong> Neutral.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]) or quadruped (<Link to="/unchevolution/claws">claws</Link>, limbs [legs, 2]).</p>
<p><strong>Base Evolutions</strong> Radiant eidolons are immune to death effects and energy drain. They can exist comfortably on the Positive Energy Plane and do not benefit or suffer from the positive-dominant planar trait. Whenever radiant eidolons are subjected to a magical healing effect, they regain 1 additional hit point per die rolled.</p>
<p>At 4th level, radiant eidolons' natural attacks can strike incorporeal targets as though they were <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapons. Radiant eidolons glow as <Link to="/spell/light">light</Link> with an effective spell level equal to half their Hit Dice (round down); they can suppress or resume this effect as a standard action.</p>
<p>At 8th level, radiant eidolons grow feathery wings, gaining the <Link to="/unchevolution/flight">flight</Link> evolution.</p>
<p>At 12th level, radiant eidolons gain the <Link to="/unchevolution/fast_healing">fast healing</Link> evolution.</p>
<p>At 16th level, radiant eidolons gain the ability to cast <Link to="/spell/cure_serious_wounds">cure serious wounds</Link> three times per day. When a radiant eidolon's summoner dies or falls unconscious within 60 feet as a result of hit point loss, the eidolon can die as an immediate action to grant the summoner the benefits of <Link to="/spell/breath_of_life">breath of life</Link>. The caster level for both abilities equals the eidolon's Hit Dice.</p>
<p>At 20th level, radiant eidolons deal an additional 2 points of damage per die rolled against undead creatures when attacking with the energy attacks or breath weapon evolutions. Whenever radiant eidolons are subjected to a magical healing effect, the effect functions at its full potential, as if enhanced by <Link to="/feat/maximize_spell">Maximize Spell</Link>.</p>
</>};
const _shadow = {title: "Shadow", jsx: <><h2 id="eidolon-shadow-shadow">Shadow</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_shadows">Blood of Shadows pg. 11</Link><br/>Summoned from the dreary shadowscapes of the Shadow Plane, shadow eidolons are grim, colorless mockeries of creatures that inhabit the Material Plane. Shadow eidolons resent being pulled into the unbearable brightness of the Material Plane. Despite this, shadow eidolons serve their summoners with somberness, acknowledging that shadow cannot exist without light.</p>
<p><strong>Alignment</strong> Any nongood.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/claws">claws</Link>, <Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]), quadruped (limbs [legs, 2], <Link to="/unchevolution/bite">bite</Link>), or serpentine (bite, <Link to="/unchevolution/improved_natural_armor">improved natural armor</Link>, <Link to="/unchevolution/reach">reach</Link> [bite], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> At 1st level, shadow eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (cold) and resistance (electricity) evolutions. They also gain the ability to cast <Link to="/spell/darkness">darkness</Link> as a spell-like ability three times per day. The caster level for this spell-like ability is equal to the eidolon's Hit Dice.</p>
<p>At 4th level, shadow eidolons effortlessly blend into the shadows, giving them <Link to="/rule/concealment">concealment</Link> (20% miss chance) in any illumination other than bright light. In <Link to="/rule/dim_light">dim light</Link> or darkness, shadow eidolons have a 50% miss chance instead of the normal 20% miss chance; this doesn't grant the eidolons total concealment. A shadow eidolon can suspend or resume this ability as a free action.</p>
<p>At 8th level, shadow eidolons gain DR 5/magic and increase the range of their darkvision to 90 feet. In addition, they add 1 point to their evolution pools.</p>
<p>At 12th level, shadow eidolons lose the ability to cast <em>darkness</em> as a spell-like ability and instead gain the ability to cast <Link to="/spell/deeper_darkness">deeper darkness</Link> as a spell-like ability three times per day. In addition, they gain the <Link to="/umr/see_in_darkness">see in darkness</Link> universal monster ability.</p>
<p>At 16th level, shadow eidolons' damage reduction increases to DR 10/magic and they gain the <Link to="/unchevolution/spell_resistance">spell resistance</Link> evolution.</p>
<p>At 20th level, shadow eidolons increase the range of their darkvision to 120 feet and gain the ability to cast <Link to="/spell/shadow_step">shadow step</Link> as a spell-like ability at will. Three times per day, a shadow eidolon can quicken this spell-like ability, functioning as the <Link to="/feat/quicken_spell_like_ability">Quicken Spell-Like Ability</Link> feat.</p>
</>};
const _storykin = {title: "Storykin", jsx: <><h2 id="eidolon-storykin-storykin">Storykin</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 26</Link><br/>The storykin are avatars of the harrow deck's cards, brought to life through the power of the <Link to="/rule/harrowed_realm">Harrowed Realm</Link>. Most of the storykin are limited in their autonomy, spending their lives acting out the roles in the stories they originated from. The form and alignment of a storykin eidolon is dependent on the harrow card the eidolon is based on. You can reference an actual <Link to="/eq-misc/harrow_deck">harrow deck</Link> for these eidolons, but you can also simulate the suit and alignment of an eidolon from a harrow deck.</p>
<p><strong>Restriction</strong> To select a storykin eidolon, the player must possess a Harrow Deck or Deluxe Harrow Deck.</p>
<p><strong>Alignment</strong> Varies.</p>
<p><strong>Base Form</strong> Bipedal (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs], <Link to="/unchevolution/slam">slam</Link>), quadruped (limbs [legs, 2], slam), or serpentine (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/grab">grab</Link> [tail slap], <Link to="/unchevolution/tail">tail</Link>, <Link to="/unchevolution/tail_slap">tail slap</Link>).</p>
<p><strong>Base Evolutions</strong> The first time a summoner summons a storykin eidolon, he must select a specific harrow card, typically one that features a creature, such as the Paladin, the Rabbit Prince, or the Tyrant. This choice determines the eidolon's base form, alignment, and overall appearance, as the eidolon resembles the creature from the chosen card. Harrow cards without an obvious creature instead manifest as a generic humanoid creature made of colorful patchwork cloth. A storykin eidolon's alignment matches the alignment of the chosen harrow card and still must be within one step of the summoner's alignment. The suit of the chosen harrow card determines the abilities of the storykin eidolon as it evolves. When the summoner gains a level, he can choose a different harrow card and thus a different base form, alignment, and appearance.</p>
<p>At 1st level, a storykin eidolon gains the <Link to="/unchevolution/resistance">resistance</Link> (sonic) evolution. In addition, storykin eidolons of the suit of hammers and suit of shields gain a +2 bonus on Fortitude saving throws. Storykin eidolons of the suit of books and suit of keys gain a +2 bonus on Reflex saving throws. Storykin eidolons of the suit of crowns and suit of stars gain a +2 bonus on Will saving throws.</p>
<p>At 4th level, a storykin eidolon gains cold resistance 10 and electricity resistance 10.</p>
<p>At 8th level, a storykin eidolon gains the <Link to="/unchevolution/ability_increase">ability increase</Link> evolution, applied to the ability score corresponding to its harrow suit.</p>
<p>At 12th level, a storykin eidolon gains immunity to bleed, poison, and stun. It also gains DR 5/adamantine.</p>
<p>At 16th level, a storykin eidolon loses the resistance (sonic) evolution and instead gains the <Link to="/unchevolution/immunity">immunity</Link> (sonic) evolution. It also gains immunity to mind-affecting effects.</p>
<p>At 20th level, a storykin eidolon gains immunity to all types of ability damage and ability drain against the ability score corresponding to its harrow suit and immunity to energy drain. It also gains the <em>ability increase</em> evolution again, applied to the same ability score that was increased at 8th level.</p>
</>};
const _twinned = {title: "Twinned", jsx: <><h2 id="eidolon-twinned-twinned">Twinned</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 18</Link><br/>Just like a summoner, a twinned eidolon learns to use weapons and magic. While twinned eidolons are ethically more flexible than most eidolons, they are quite adamant about being treated as equals and not as servants. They demonstrate an eerie consistency with the summoner's manner of thinking, providing similar answers to questions and reacting similarly to startling events. This subtype is restricted to <Link to="/arc-unchained_summoner/twinned_summoner">twinned summoners</Link>.</p>
<p><strong>Alignment</strong> Any.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/limbs">limbs</Link> [arms], limbs [legs]).</p>
<p><strong>Base Evolutions</strong> A twinned eidolon gains the <Link to="/unchevolution/weapon_training">weapon training</Link> evolution. The twinned eidolon also gains the <Link to="/unchevolution/skilled">skilled</Link> (Disguise) evolution. The racial bonus provided by this evolution is doubled when the eidolon is impersonating the twinned summoner.</p>
<p>At 4th level, a twinned eidolon can cast a summoner spell once per day as a spell-like ability. The spell must be one known by the eidolon's summoner and must be at least 1 level lower than the highest-level spell the summoner can cast. The eidolon must have a Charisma score of at least 10 + the spell level. The caster level for this spell-like ability is equal to the eidolon's Hit Dice minus 2. The save DC is 10 + half the eidolon's HD + the eidolon's Charisma modifier. At 8th level, a twinned eidolon gains the <Link to="/unchevolution/shared_slot">shared slot</Link> evolution.</p>
<p>At 12th level, a twinned eidolon gains DR 5/magic. The eidolon also gains the <Link to="/unchevolution/extra_feat">extra feat</Link> evolution.</p>
<p>At 16th level, a twinned eidolon gains the <em>skilled</em> evolution and the <Link to="/unchevolution/ability_increase">ability increase</Link> evolution, applied to a skill and an ability score of the summoner's choice.</p>
<p>At 20th level, a twinned eidolon gains <Link to="/umr/fast_healing">fast healing</Link> 5.</p>
</>};
const _void = {title: "Void", jsx: <><h2 id="eidolon-void-void">Void</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 25</Link><br/>Like the sharp-angled <Link to="/monster/sceaduinar">sceaduinars</Link> they resemble, void eidolons exult in entropy and resent anything bearing even a hint of life - including their summoners.</p>
<p><strong>Alignment</strong> Neutral or neutral evil.</p>
<p><strong>Base Form</strong> Biped (<Link to="/unchevolution/bite">bite</Link>, <Link to="/unchevolution/limbs">limbs</Link> [legs], <Link to="/unchevolution/skilled">skilled</Link> [Stealth], <Link to="/unchevolution/wing_buffet">wing buffet</Link>).</p>
<p><strong>Base Evolutions</strong> Void eidolons have <Link to="/umr/negative_energy_affinity">negative energy affinity</Link> and are immune to death effects, disease, energy drain, and poison.</p>
<p>At 4th level, void eidolons gain the <Link to="/unchevolution/resistance">resistance</Link> (cold) evolution. Their natural attacks can strike incorporeal targets as though they were <Link to="/magic-enh/ghost_touch">ghost touch</Link> weapons.</p>
<p>At 8th level, void eidolons can use their wings to fly, gaining the <Link to="/unchevolution/flight">flight</Link> evolution. When selecting the <Link to="/unchevolution/energy_attacks">energy attacks</Link> evolution, void eidolons can instead choose to deal 1d6 points of negative energy damage on a successful hit; this damage does not heal creatures.</p>
<p>At 12th level, void eidolons gain the <Link to="/umr/lifesense">lifesense</Link> ability. They also gain the <Link to="/umr/energy_drain">energy drain</Link> ability (1 negative level) with their bite attacks, though they can drain only a total number of levels per day equal to half their Hit Dice (rounded down).</p>
<p>At 16th level, void eidolons lose the resistance (cold) evolution and instead gain the <Link to="/unchevolution/immunity">immunity</Link> (cold) evolution. They also gain DR 5/adamantine.</p>
<p>At 20th level, void eidolons can bestow up to 2 negative levels with a successful bite attack, and the number of negative levels they can bestow per day increases by their Constitution modifier. Their damage reduction increases to DR 10/adamantine.</p>
</>};
export default {not_found:_not_found,aberrant:_aberrant,aeon:_aeon,agathion:_agathion,ancestor:_ancestor,angel:_angel,archon:_archon,astral:_astral,azata:_azata,daemon:_daemon,deepwater:_deepwater,demon:_demon,devil:_devil,div:_div,elemental:_elemental,genie:_genie,inevitable:_inevitable,kami:_kami,kyton:_kyton,plant:_plant,protean:_protean,psychopomp:_psychopomp,radiant:_radiant,shadow:_shadow,storykin:_storykin,twinned:_twinned,void:_void}